/**
 * User notification preferences model.
 *
 * Supports per-channel notification settings (email, SMS, webhook).
 * Each channel has its own enabled flag and subscribed types.
 * Channel-specific extensions (e.g., email frequency) are layered on top.
 *
 * Design: opt-out model — missing channel preferences = all notifications allowed.
 * Backward compatible: the `email` field is always present with defaults.
 * SMS and webhook fields are optional — absent means "use defaults (all enabled)".
 */

import type { NotificationType } from './notification.js';

/**
 * Base preferences shared by all notification channels.
 */
export interface ChannelPreferences {
  /** Whether this channel is enabled for the user. */
  enabled: boolean;
  /** Notification types the user is subscribed to on this channel. */
  subscribedTypes: NotificationType[];
}

/**
 * Email delivery frequency.
 * - 'realtime': Send emails immediately as events occur.
 * - 'daily': Batch into a daily digest (not yet implemented).
 * - 'weekly': Batch into a weekly digest (not yet implemented).
 */
export type EmailFrequency = 'realtime' | 'daily' | 'weekly';

/**
 * Email-specific notification settings.
 */
export interface EmailPreferences extends ChannelPreferences {
  /** Delivery frequency for non-urgent emails. */
  frequency: EmailFrequency;
}

/**
 * SMS-specific notification settings.
 */
export interface SmsPreferences extends ChannelPreferences {}

/**
 * Webhook-specific notification settings.
 */
export interface WebhookPreferences extends ChannelPreferences {}

/**
 * A user's full notification preferences.
 */
export interface UserPreferences {
  id: string;
  userId: string;
  email: EmailPreferences;
  sms?: SmsPreferences;
  webhook?: WebhookPreferences;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for creating user preferences (userId required, rest optional with defaults).
 */
export interface CreateUserPreferencesInput {
  userId: string;
  email?: Partial<EmailPreferences>;
  sms?: Partial<SmsPreferences>;
  webhook?: Partial<WebhookPreferences>;
}

/**
 * Input for updating user preferences.
 */
export interface UpdateUserPreferencesInput {
  email?: Partial<EmailPreferences>;
  sms?: Partial<SmsPreferences>;
  webhook?: Partial<WebhookPreferences>;
}

/** All notification types for default subscriptions. */
const ALL_NOTIFICATION_TYPES: NotificationType[] = [
  'order_confirmation',
  'order_status_update',
  'user_welcome',
  'user_update',
  'system_alert',
];

/**
 * Default email preferences for new users — all notifications enabled, realtime delivery.
 */
export const DEFAULT_EMAIL_PREFERENCES: EmailPreferences = {
  enabled: true,
  frequency: 'realtime',
  subscribedTypes: [...ALL_NOTIFICATION_TYPES],
};

/**
 * Default SMS preferences — all notifications enabled.
 */
export const DEFAULT_SMS_PREFERENCES: SmsPreferences = {
  enabled: true,
  subscribedTypes: [...ALL_NOTIFICATION_TYPES],
};

/**
 * Default webhook preferences — all notifications enabled.
 */
export const DEFAULT_WEBHOOK_PREFERENCES: WebhookPreferences = {
  enabled: true,
  subscribedTypes: [...ALL_NOTIFICATION_TYPES],
};

/**
 * Get the default ChannelPreferences for a given channel.
 */
export function getDefaultChannelPreferences(channel: 'email'): EmailPreferences;
export function getDefaultChannelPreferences(channel: 'sms'): SmsPreferences;
export function getDefaultChannelPreferences(channel: 'webhook'): WebhookPreferences;
export function getDefaultChannelPreferences(channel: string): ChannelPreferences;
export function getDefaultChannelPreferences(channel: string): ChannelPreferences {
  switch (channel) {
    case 'email':
      return { ...DEFAULT_EMAIL_PREFERENCES };
    case 'sms':
      return { ...DEFAULT_SMS_PREFERENCES };
    case 'webhook':
      return { ...DEFAULT_WEBHOOK_PREFERENCES };
    default:
      return { enabled: true, subscribedTypes: [...ALL_NOTIFICATION_TYPES] };
  }
}

/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with preference-specific query methods.
 * Supports multi-channel preferences (email, SMS, webhook).
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserPreferences } from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import type { EmailFrequency } from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    const prefs: UserPreferences = {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: {
        enabled: record['emailEnabled'] as boolean,
        frequency: record['emailFrequency'] as EmailFrequency,
        subscribedTypes: JSON.parse(record['emailSubscribedTypes'] as string) as NotificationType[],
      },
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };

    // Deserialize optional SMS preferences
    if (record['smsEnabled'] !== undefined) {
      prefs.sms = {
        enabled: record['smsEnabled'] as boolean,
        subscribedTypes: JSON.parse(record['smsSubscribedTypes'] as string) as NotificationType[],
      };
    }

    // Deserialize optional webhook preferences
    if (record['webhookEnabled'] !== undefined) {
      prefs.webhook = {
        enabled: record['webhookEnabled'] as boolean,
        subscribedTypes: JSON.parse(record['webhookSubscribedTypes'] as string) as NotificationType[],
      };
    }

    return prefs;
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    const record: DatabaseRecord = {
      id: entity.id,
      userId: entity.userId,
      emailEnabled: entity.email.enabled,
      emailFrequency: entity.email.frequency,
      emailSubscribedTypes: JSON.stringify(entity.email.subscribedTypes),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };

    if (entity.sms) {
      record['smsEnabled'] = entity.sms.enabled;
      record['smsSubscribedTypes'] = JSON.stringify(entity.sms.subscribedTypes);
    }

    if (entity.webhook) {
      record['webhookEnabled'] = entity.webhook.enabled;
      record['webhookSubscribedTypes'] = JSON.stringify(entity.webhook.subscribedTypes);
    }

    return record;
  }

  /**
   * Find preferences by user ID.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

/**
 * Pure validation functions for notification operations.
 *
 * No side effects, no database calls — these functions evaluate
 * notification rules using only the data provided.
 */

import type { UserPreferences, ChannelPreferences } from '../models/user-preferences.js';
import type { NotificationPayload, NotificationChannel } from '../models/notification.js';

/**
 * Get channel-specific preferences from a UserPreferences object.
 * Returns undefined if no preferences are set for the channel.
 */
function getChannelPreferences(
  prefs: UserPreferences,
  channel: NotificationChannel,
): ChannelPreferences | undefined {
  switch (channel) {
    case 'email':
      return prefs.email;
    case 'sms':
      return prefs.sms;
    case 'webhook':
      return prefs.webhook;
    default:
      return undefined;
  }
}

/**
 * Determine whether a notification should be sent based on user preferences.
 *
 * Rules:
 * - Urgent priority notifications always go through.
 * - If no preferences exist, notifications are allowed (opt-out model).
 * - Per-channel checks: if channel preferences exist, check enabled + subscribedTypes.
 * - If no channel-specific preferences are set, the notification is allowed (opt-out).
 */
export function shouldSendNotification(
  prefs: UserPreferences | undefined,
  payload: NotificationPayload,
): boolean {
  // Urgent notifications always go through
  if (payload.priority === 'urgent') {
    return true;
  }

  // No preferences = default allow (opt-out model)
  if (!prefs) {
    return true;
  }

  // Get channel-specific preferences
  const channelPrefs = getChannelPreferences(prefs, payload.channel);

  // No preferences for this channel = default allow (opt-out model)
  if (!channelPrefs) {
    return true;
  }

  // Check if channel is enabled
  if (!channelPrefs.enabled) {
    return false;
  }

  // Check if notification type is subscribed
  if (!channelPrefs.subscribedTypes.includes(payload.type)) {
    return false;
  }

  return true;
}

/**
 * Preferences service — manages user notification preferences.
 *
 * Provides CRUD operations for user preferences and a query method
 * used by the NotificationService to check whether a notification
 * should be delivered. Supports per-channel preferences (email, SMS, webhook).
 */

import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type {
  UserPreferences,
  CreateUserPreferencesInput,
  UpdateUserPreferencesInput,
} from '../models/user-preferences.js';
import type { NotificationPayload } from '../models/notification.js';
import {
  DEFAULT_EMAIL_PREFERENCES,
  DEFAULT_SMS_PREFERENCES,
  DEFAULT_WEBHOOK_PREFERENCES,
} from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';
import { shouldSendNotification as checkNotificationPreferences } from '../validators/notification.validator.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private repository: PreferencesRepository) {}

  /**
   * Create preferences for a user. Uses defaults for any unspecified fields.
   * Throws if preferences already exist for the user.
   */
  createPreferences(input: CreateUserPreferencesInput): UserPreferences {
    const existing = this.repository.findByUserId(input.userId);
    if (existing) {
      throw new Error(`Preferences already exist for user: ${input.userId}`);
    }

    const now = new Date();
    const prefs: UserPreferences = {
      id: generatePreferencesId(),
      userId: input.userId,
      email: {
        ...DEFAULT_EMAIL_PREFERENCES,
        ...input.email,
        subscribedTypes: input.email?.subscribedTypes ?? DEFAULT_EMAIL_PREFERENCES.subscribedTypes,
      },
      createdAt: now,
      updatedAt: now,
    };

    // Add SMS preferences if provided
    if (input.sms) {
      prefs.sms = {
        ...DEFAULT_SMS_PREFERENCES,
        ...input.sms,
        subscribedTypes: input.sms.subscribedTypes ?? DEFAULT_SMS_PREFERENCES.subscribedTypes,
      };
    }

    // Add webhook preferences if provided
    if (input.webhook) {
      prefs.webhook = {
        ...DEFAULT_WEBHOOK_PREFERENCES,
        ...input.webhook,
        subscribedTypes: input.webhook.subscribedTypes ?? DEFAULT_WEBHOOK_PREFERENCES.subscribedTypes,
      };
    }

    this.repository.save(prefs);
    this.logger.info(`Created preferences for user: ${input.userId}`);
    return prefs;
  }

  /**
   * Get preferences for a user. Returns undefined if none exist.
   */
  getPreferences(userId: string): UserPreferences | undefined {
    return this.repository.findByUserId(userId);
  }

  /**
   * Get preferences for a user, creating defaults if none exist.
   */
  getOrCreatePreferences(userId: string): UserPreferences {
    const existing = this.repository.findByUserId(userId);
    if (existing) {
      return existing;
    }
    return this.createPreferences({ userId });
  }

  /**
   * Update a user's preferences. Only specified fields are changed.
   */
  updatePreferences(userId: string, input: UpdateUserPreferencesInput): UserPreferences {
    const existing = this.repository.findByUserId(userId);
    if (!existing) {
      throw new Error(`No preferences found for user: ${userId}`);
    }

    const updated: UserPreferences = {
      ...existing,
      email: {
        ...existing.email,
        ...input.email,
        subscribedTypes: input.email?.subscribedTypes ?? existing.email.subscribedTypes,
      },
      updatedAt: new Date(),
    };

    // Update SMS preferences
    if (input.sms) {
      const existingSms = existing.sms ?? DEFAULT_SMS_PREFERENCES;
      updated.sms = {
        ...existingSms,
        ...input.sms,
        subscribedTypes: input.sms.subscribedTypes ?? existingSms.subscribedTypes,
      };
    } else if (existing.sms) {
      updated.sms = existing.sms;
    }

    // Update webhook preferences
    if (input.webhook) {
      const existingWebhook = existing.webhook ?? DEFAULT_WEBHOOK_PREFERENCES;
      updated.webhook = {
        ...existingWebhook,
        ...input.webhook,
        subscribedTypes: input.webhook.subscribedTypes ?? existingWebhook.subscribedTypes,
      };
    } else if (existing.webhook) {
      updated.webhook = existing.webhook;
    }

    this.repository.update(existing.id, updated);
    this.logger.info(`Updated preferences for user: ${userId}`);
    return updated;
  }

  /**
   * Delete a user's preferences.
   */
  deletePreferences(userId: string): boolean {
    const existing = this.repository.findByUserId(userId);
    if (!existing) {
      return false;
    }
    this.repository.delete(existing.id);
    this.logger.info(`Deleted preferences for user: ${userId}`);
    return true;
  }

  /**
   * Check whether a notification should be delivered to the user based on their preferences.
   *
   * Rules (per channel):
   * - If no preferences exist, notifications are allowed (opt-out model).
   * - If channel is disabled, notifications for that channel are blocked.
   * - If the notification type is not in the channel's subscribedTypes, it is blocked.
   * - 'urgent' priority notifications always go through regardless of preferences.
   */
  shouldSendNotification(userId: string, payload: NotificationPayload): boolean {
    const prefs = this.repository.findByUserId(userId);
    const allowed = checkNotificationPreferences(prefs, payload);

    if (!allowed) {
      this.logger.info(
        `Notification blocked by preferences for user ${userId}: ${payload.type} via ${payload.channel}`,
      );
    }

    return allowed;
  }
}

