import { describe, it, expect } from 'vitest';
import { shouldSendNotification } from '../../src/validators/notification.validator.js';
import type { UserPreferences } from '../../src/models/user-preferences.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides: Partial<NotificationPayload> = {}): NotificationPayload {
  return {
    recipient: 'user@example.com',
    subject: 'Test',
    body: 'Test body',
    channel: 'email',
    type: 'order_confirmation',
    priority: 'normal',
    ...overrides,
  };
}

function makePrefs(overrides: Partial<Pick<UserPreferences, 'email' | 'sms' | 'webhook'>> = {}): UserPreferences {
  return {
    id: 'pref-1',
    userId: 'user-1',
    email: {
      enabled: true,
      frequency: 'realtime',
      subscribedTypes: [
        'order_confirmation',
        'order_status_update',
        'user_welcome',
        'user_update',
        'system_alert',
      ],
    },
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

describe('Notification Validators', () => {
  describe('shouldSendNotification', () => {
    it('should allow notification when no preferences exist (opt-out model)', () => {
      expect(shouldSendNotification(undefined, makePayload())).toBe(true);
    });

    it('should allow notification when preferences allow it', () => {
      expect(shouldSendNotification(makePrefs(), makePayload())).toBe(true);
    });

    it('should block notification when email is disabled', () => {
      const prefs = makePrefs({
        email: { enabled: false, frequency: 'realtime', subscribedTypes: ['order_confirmation'] },
      });
      expect(shouldSendNotification(prefs, makePayload())).toBe(false);
    });

    it('should block notification when type is not subscribed', () => {
      const prefs = makePrefs({
        email: { enabled: true, frequency: 'realtime', subscribedTypes: ['system_alert'] },
      });
      expect(
        shouldSendNotification(prefs, makePayload({ type: 'order_confirmation' })),
      ).toBe(false);
    });

    it('should allow urgent notifications even when email is disabled', () => {
      const prefs = makePrefs({
        email: { enabled: false, frequency: 'realtime', subscribedTypes: [] },
      });
      expect(
        shouldSendNotification(prefs, makePayload({ priority: 'urgent' })),
      ).toBe(true);
    });

    it('should allow urgent notifications even when type is not subscribed', () => {
      const prefs = makePrefs({
        email: { enabled: true, frequency: 'realtime', subscribedTypes: [] },
      });
      expect(
        shouldSendNotification(prefs, makePayload({ priority: 'urgent' })),
      ).toBe(true);
    });

    it('should allow notification for subscribed type', () => {
      const prefs = makePrefs({
        email: { enabled: true, frequency: 'realtime', subscribedTypes: ['order_confirmation'] },
      });
      expect(
        shouldSendNotification(prefs, makePayload({ type: 'order_confirmation' })),
      ).toBe(true);
    });
  });

  describe('shouldSendNotification — SMS channel', () => {
    it('should allow SMS when no SMS preferences are set (opt-out)', () => {
      const prefs = makePrefs();
      expect(
        shouldSendNotification(prefs, makePayload({ channel: 'sms' })),
      ).toBe(true);
    });

    it('should allow SMS when SMS is enabled and type is subscribed', () => {
      const prefs = makePrefs({
        sms: { enabled: true, subscribedTypes: ['order_confirmation'] },
      });
      expect(
        shouldSendNotification(prefs, makePayload({ channel: 'sms', type: 'order_confirmation' })),
      ).toBe(true);
    });

    it('should block SMS when SMS is disabled', () => {
      const prefs = makePrefs({
        sms: { enabled: false, subscribedTypes: ['order_confirmation'] },
      });
      expect(
        shouldSendNotification(prefs, makePayload({ channel: 'sms' })),
      ).toBe(false);
    });

    it('should block SMS when type is not in SMS subscribedTypes', () => {
      const prefs = makePrefs({
        sms: { enabled: true, subscribedTypes: ['system_alert'] },
      });
      expect(
        shouldSendNotification(prefs, makePayload({ channel: 'sms', type: 'order_confirmation' })),
      ).toBe(false);
    });

    it('should allow urgent SMS even when SMS is disabled', () => {
      const prefs = makePrefs({
        sms: { enabled: false, subscribedTypes: [] },
      });
      expect(
        shouldSendNotification(prefs, makePayload({ channel: 'sms', priority: 'urgent' })),
      ).toBe(true);
    });

    it('should not affect email preferences when SMS is disabled', () => {
      const prefs = makePrefs({
        sms: { enabled: false, subscribedTypes: [] },
      });
      // Email should still be allowed
      expect(shouldSendNotification(prefs, makePayload({ channel: 'email' }))).toBe(true);
    });
  });

  describe('shouldSendNotification — webhook channel', () => {
    it('should allow webhook when no webhook preferences are set (opt-out)', () => {
      const prefs = makePrefs();
      expect(
        shouldSendNotification(prefs, makePayload({ channel: 'webhook' })),
      ).toBe(true);
    });

    it('should allow webhook when enabled and type is subscribed', () => {
      const prefs = makePrefs({
        webhook: { enabled: true, subscribedTypes: ['order_confirmation'] },
      });
      expect(
        shouldSendNotification(prefs, makePayload({ channel: 'webhook', type: 'order_confirmation' })),
      ).toBe(true);
    });

    it('should block webhook when disabled', () => {
      const prefs = makePrefs({
        webhook: { enabled: false, subscribedTypes: ['order_confirmation'] },
      });
      expect(
        shouldSendNotification(prefs, makePayload({ channel: 'webhook' })),
      ).toBe(false);
    });

    it('should block webhook when type is not subscribed', () => {
      const prefs = makePrefs({
        webhook: { enabled: true, subscribedTypes: ['system_alert'] },
      });
      expect(
        shouldSendNotification(prefs, makePayload({ channel: 'webhook', type: 'order_confirmation' })),
      ).toBe(false);
    });

    it('should allow urgent webhook even when disabled', () => {
      const prefs = makePrefs({
        webhook: { enabled: false, subscribedTypes: [] },
      });
      expect(
        shouldSendNotification(prefs, makePayload({ channel: 'webhook', priority: 'urgent' })),
      ).toBe(true);
    });
  });

  describe('shouldSendNotification — cross-channel isolation', () => {
    it('should independently evaluate each channel', () => {
      const prefs = makePrefs({
        email: { enabled: false, frequency: 'realtime', subscribedTypes: [] },
        sms: { enabled: true, subscribedTypes: ['order_confirmation'] },
        webhook: { enabled: true, subscribedTypes: ['system_alert'] },
      });

      // Email blocked
      expect(shouldSendNotification(prefs, makePayload({ channel: 'email' }))).toBe(false);
      // SMS allowed for subscribed type
      expect(shouldSendNotification(prefs, makePayload({ channel: 'sms', type: 'order_confirmation' }))).toBe(true);
      // SMS blocked for non-subscribed type
      expect(shouldSendNotification(prefs, makePayload({ channel: 'sms', type: 'system_alert' }))).toBe(false);
      // Webhook allowed for subscribed type
      expect(shouldSendNotification(prefs, makePayload({ channel: 'webhook', type: 'system_alert' }))).toBe(true);
      // Webhook blocked for non-subscribed type
      expect(shouldSendNotification(prefs, makePayload({ channel: 'webhook', type: 'order_confirmation' }))).toBe(false);
    });
  });
});

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import {
  DEFAULT_EMAIL_PREFERENCES,
  DEFAULT_SMS_PREFERENCES,
  DEFAULT_WEBHOOK_PREFERENCES,
} from '../../src/models/user-preferences.js';
import type { NotificationPayload } from '../../src/models/notification.js';

describe('PreferencesService', () => {
  let db: Database;
  let repository: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    repository = new PreferencesRepository(db);
    service = new PreferencesService(repository);
    resetPreferencesIdCounter();
  });

  describe('createPreferences', () => {
    it('should create preferences with defaults', () => {
      const prefs = service.createPreferences({ userId: 'user-1' });

      expect(prefs.userId).toBe('user-1');
      expect(prefs.id).toBe('pref-0001');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('realtime');
      expect(prefs.email.subscribedTypes).toEqual(DEFAULT_EMAIL_PREFERENCES.subscribedTypes);
    });

    it('should create preferences with custom email settings', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        email: {
          enabled: false,
          frequency: 'daily',
          subscribedTypes: ['order_confirmation'],
        },
      });

      expect(prefs.email.enabled).toBe(false);
      expect(prefs.email.frequency).toBe('daily');
      expect(prefs.email.subscribedTypes).toEqual(['order_confirmation']);
    });

    it('should throw if preferences already exist for user', () => {
      service.createPreferences({ userId: 'user-1' });

      expect(() => service.createPreferences({ userId: 'user-1' })).toThrow(
        'Preferences already exist for user: user-1',
      );
    });

    it('should generate sequential IDs', () => {
      const p1 = service.createPreferences({ userId: 'user-1' });
      const p2 = service.createPreferences({ userId: 'user-2' });

      expect(p1.id).toBe('pref-0001');
      expect(p2.id).toBe('pref-0002');
    });

    it('should create preferences with SMS settings', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        sms: { enabled: true, subscribedTypes: ['order_confirmation', 'system_alert'] },
      });

      expect(prefs.sms).toBeDefined();
      expect(prefs.sms!.enabled).toBe(true);
      expect(prefs.sms!.subscribedTypes).toEqual(['order_confirmation', 'system_alert']);
    });

    it('should create preferences with webhook settings', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        webhook: { enabled: false },
      });

      expect(prefs.webhook).toBeDefined();
      expect(prefs.webhook!.enabled).toBe(false);
      expect(prefs.webhook!.subscribedTypes).toEqual(DEFAULT_WEBHOOK_PREFERENCES.subscribedTypes);
    });

    it('should create preferences with all channels', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        email: { enabled: true },
        sms: { enabled: true, subscribedTypes: ['system_alert'] },
        webhook: { enabled: false },
      });

      expect(prefs.email.enabled).toBe(true);
      expect(prefs.sms!.enabled).toBe(true);
      expect(prefs.sms!.subscribedTypes).toEqual(['system_alert']);
      expect(prefs.webhook!.enabled).toBe(false);
    });

    it('should not set SMS/webhook when not provided', () => {
      const prefs = service.createPreferences({ userId: 'user-1' });

      expect(prefs.sms).toBeUndefined();
      expect(prefs.webhook).toBeUndefined();
    });
  });

  describe('getPreferences', () => {
    it('should return preferences for existing user', () => {
      service.createPreferences({ userId: 'user-1' });

      const prefs = service.getPreferences('user-1');
      expect(prefs).toBeDefined();
      expect(prefs!.userId).toBe('user-1');
    });

    it('should return undefined for non-existent user', () => {
      expect(service.getPreferences('user-999')).toBeUndefined();
    });
  });

  describe('getOrCreatePreferences', () => {
    it('should return existing preferences', () => {
      const created = service.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      const fetched = service.getOrCreatePreferences('user-1');
      expect(fetched.id).toBe(created.id);
      expect(fetched.email.enabled).toBe(false);
    });

    it('should create default preferences if none exist', () => {
      const prefs = service.getOrCreatePreferences('user-1');

      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('realtime');
    });
  });

  describe('updatePreferences', () => {
    it('should update email enabled flag', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        email: { enabled: false },
      });

      expect(updated.email.enabled).toBe(false);
      expect(updated.email.frequency).toBe('realtime'); // unchanged
    });

    it('should update subscribed types', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        email: { subscribedTypes: ['order_confirmation', 'system_alert'] },
      });

      expect(updated.email.subscribedTypes).toEqual(['order_confirmation', 'system_alert']);
    });

    it('should update frequency', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        email: { frequency: 'weekly' },
      });

      expect(updated.email.frequency).toBe('weekly');
    });

    it('should throw if no preferences exist', () => {
      expect(() =>
        service.updatePreferences('user-999', { email: { enabled: false } }),
      ).toThrow('No preferences found for user: user-999');
    });

    it('should update the updatedAt timestamp', () => {
      const created = service.createPreferences({ userId: 'user-1' });
      const originalUpdatedAt = created.updatedAt;

      const updated = service.updatePreferences('user-1', {
        email: { enabled: false },
      });

      expect(updated.updatedAt.getTime()).toBeGreaterThanOrEqual(originalUpdatedAt.getTime());
    });

    it('should add SMS preferences via update', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        sms: { enabled: true, subscribedTypes: ['order_confirmation'] },
      });

      expect(updated.sms).toBeDefined();
      expect(updated.sms!.enabled).toBe(true);
      expect(updated.sms!.subscribedTypes).toEqual(['order_confirmation']);
    });

    it('should add webhook preferences via update', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        webhook: { enabled: true, subscribedTypes: ['system_alert'] },
      });

      expect(updated.webhook).toBeDefined();
      expect(updated.webhook!.enabled).toBe(true);
      expect(updated.webhook!.subscribedTypes).toEqual(['system_alert']);
    });

    it('should update existing SMS preferences', () => {
      service.createPreferences({
        userId: 'user-1',
        sms: { enabled: true, subscribedTypes: ['order_confirmation'] },
      });

      const updated = service.updatePreferences('user-1', {
        sms: { enabled: false },
      });

      expect(updated.sms!.enabled).toBe(false);
      expect(updated.sms!.subscribedTypes).toEqual(['order_confirmation']); // preserved
    });

    it('should preserve SMS preferences when only updating email', () => {
      service.createPreferences({
        userId: 'user-1',
        sms: { enabled: true, subscribedTypes: ['system_alert'] },
      });

      const updated = service.updatePreferences('user-1', {
        email: { enabled: false },
      });

      expect(updated.sms!.enabled).toBe(true);
      expect(updated.sms!.subscribedTypes).toEqual(['system_alert']);
    });

    it('should update multiple channels simultaneously', () => {
      service.createPreferences({
        userId: 'user-1',
        sms: { enabled: true },
        webhook: { enabled: true },
      });

      const updated = service.updatePreferences('user-1', {
        email: { enabled: false },
        sms: { enabled: false },
        webhook: { subscribedTypes: ['system_alert'] },
      });

      expect(updated.email.enabled).toBe(false);
      expect(updated.sms!.enabled).toBe(false);
      expect(updated.webhook!.subscribedTypes).toEqual(['system_alert']);
    });
  });

  describe('deletePreferences', () => {
    it('should delete existing preferences', () => {
      service.createPreferences({ userId: 'user-1' });

      expect(service.deletePreferences('user-1')).toBe(true);
      expect(service.getPreferences('user-1')).toBeUndefined();
    });

    it('should return false for non-existent preferences', () => {
      expect(service.deletePreferences('user-999')).toBe(false);
    });
  });

  describe('shouldSendNotification', () => {
    const makePayload = (overrides: Partial<NotificationPayload> = {}): NotificationPayload => ({
      recipient: 'user@example.com',
      subject: 'Test',
      body: 'Test body',
      channel: 'email',
      type: 'order_confirmation',
      priority: 'normal',
      ...overrides,
    });

    it('should allow notifications when no preferences exist (opt-out model)', () => {
      expect(service.shouldSendNotification('user-1', makePayload())).toBe(true);
    });

    it('should allow notifications when email is enabled and type is subscribed', () => {
      service.createPreferences({ userId: 'user-1' });

      expect(service.shouldSendNotification('user-1', makePayload())).toBe(true);
    });

    it('should block notifications when email is disabled', () => {
      service.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      expect(service.shouldSendNotification('user-1', makePayload())).toBe(false);
    });

    it('should block notifications for unsubscribed types', () => {
      service.createPreferences({
        userId: 'user-1',
        email: { subscribedTypes: ['system_alert'] },
      });

      expect(
        service.shouldSendNotification('user-1', makePayload({ type: 'order_confirmation' })),
      ).toBe(false);
    });

    it('should allow subscribed types', () => {
      service.createPreferences({
        userId: 'user-1',
        email: { subscribedTypes: ['system_alert'] },
      });

      expect(
        service.shouldSendNotification('user-1', makePayload({ type: 'system_alert' })),
      ).toBe(true);
    });

    it('should always allow urgent priority notifications', () => {
      service.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      expect(
        service.shouldSendNotification('user-1', makePayload({ priority: 'urgent' })),
      ).toBe(true);
    });

    it('should allow SMS when no SMS preferences are set (opt-out)', () => {
      service.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      expect(
        service.shouldSendNotification('user-1', makePayload({ channel: 'sms' })),
      ).toBe(true);
    });

    it('should block SMS when SMS preferences disable it', () => {
      service.createPreferences({
        userId: 'user-1',
        sms: { enabled: false },
      });

      expect(
        service.shouldSendNotification('user-1', makePayload({ channel: 'sms' })),
      ).toBe(false);
    });

    it('should block SMS for unsubscribed types', () => {
      service.createPreferences({
        userId: 'user-1',
        sms: { enabled: true, subscribedTypes: ['system_alert'] },
      });

      expect(
        service.shouldSendNotification('user-1', makePayload({ channel: 'sms', type: 'order_confirmation' })),
      ).toBe(false);
    });

    it('should block webhook when webhook preferences disable it', () => {
      service.createPreferences({
        userId: 'user-1',
        webhook: { enabled: false },
      });

      expect(
        service.shouldSendNotification('user-1', makePayload({ channel: 'webhook' })),
      ).toBe(false);
    });

    it('should allow webhook when no webhook preferences are set (opt-out)', () => {
      service.createPreferences({ userId: 'user-1' });

      expect(
        service.shouldSendNotification('user-1', makePayload({ channel: 'webhook' })),
      ).toBe(true);
    });
  });
});
